define(["core/ajax","core/templates"],function(Ajax,Templates){var loadPage=function(container,directionId,page){container.classList.add("block-announcements-loading");var request=Ajax.call([{methodname:"block_announcements_get_page",args:{directionid:directionId,page:page}}]);request[0].then(function(response){var tiles=response.tiles.map(function(tile){var t={name:tile.name,text:tile.text,date:tile.date,attachcount:tile.attachcount,hasattachments:tile.hasattachments,viewurl:tile.viewurl};if(tile.isadmin){t.isadmin=true;t.directionname=tile.directionname||""}return t});var pages=[];for(var i=0;i<response.totalpages;i++){pages.push({pagenum:i+1,page:i,active:i===response.currentpage})}var templateData={hastiles:tiles.length>0,tiles:tiles,haspagination:response.totalpages>1,pages:pages};return Templates.renderForPromise("block_announcements/content",templateData)}).then(function(result){container.innerHTML=result.html;Templates.runTemplateJS(result.js);container.classList.remove("block-announcements-loading");return}).catch(function(){container.classList.remove("block-announcements-loading")})};return{init:function(directionId,currentPage){var container=document.querySelector('[data-region="block-announcements"]');if(!container){return}container.addEventListener("click",function(e){var pageLink=e.target.closest("[data-page]");if(!pageLink){return}e.preventDefault();var page=parseInt(pageLink.dataset.page,10);loadPage(container,directionId,page)})}}});
